In C++, you can start a new process and connect one file descriptor to its input and output using the `popen` function from the `<cstdio>` library for simpler cases, or using more low-level functions like `fork`, `exec`, and file descriptor manipulation with `dup2` from the `<unistd.h>` library for more control. Here’s an example using `popen`:

```cpp
#include <cstdio>

int main() {
    FILE* pipe = popen("command", "w");
    if (!pipe) {
        // Handle error
        return 1;
    }
    fprintf(pipe, "Hello, World!\n");
    pclose(pipe);
    return 0;
}
```

For more complex scenarios, you might want to use `fork`, `exec`, and `dup2`:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <cstdio>

int main() {
    pid_t pid;
    int fd[2];
    pipe(fd);

    pid = fork();
    if (pid < 0) {
        // Handle error
        return 1;
    } else if (pid == 0) { // Child process
        close(fd[1]); // Close unused write end
        dup2(fd[0], STDIN_FILENO); // Redirect stdin
        close(fd[0]); // Close the original file descriptor
        execlp("command", "command", NULL); // Replace child process
        perror("execlp"); // Handle error
        return 1;
    } else { // Parent process
        close(fd[0]); // Close unused read end
        FILE* pipe = fdopen(fd[1], "w");
        if (!pipe) {
            // Handle error
            return 1;
        }
        fprintf(pipe, "Hello, World!\n");
        fclose(pipe);
        wait(NULL); // Wait for child to terminate
    }
    return 0;
}
```

This example sets up a pipe between the parent and child processes, redirects the child's standard input to the pipe, and writes to the pipe from the parent.
